const preview = {
    globalTypes: {
        customer: {
            name: 'Customer Theme',
            description: 'Switch between customer design tokens',
            toolbar: {
                icon: 'paintbrush',
                items: [
                    { value: 'ds-bank', title: 'DS Bank' },
                    { value: 'ng-bank', title: 'NG Bank' },
                ],
                dynamicTitle: true,
            },
        },
    },
    initialGlobals: {
        customer: 'ds-bank',
    },
    decorators: [
        (story, context) => {
            const customer = context.globals['customer'] || 'ds-bank';
            // Dynamically load the correct customer CSS variables
            const existingLink = document.getElementById('ds-customer-tokens');
            if (existingLink)
                existingLink.remove();
            const link = document.createElement('link');
            link.id = 'ds-customer-tokens';
            link.rel = 'stylesheet';
            link.href =
                customer === 'ng-bank'
                    ? 'ng-bank-variables.css'
                    : 'ds-bank-variables.css';
            document.head.appendChild(link);
            return story();
        },
    ],
    parameters: {
        controls: { expanded: true },
    },
};
export default preview;
